import{_ as a,c as e,o as r,aj as l,ak as i,as as o,at as d,au as n,av as s,aw as p,ax as _,ay as h}from"./chunks/framework.CoirRWyn.js";const k=JSON.parse('{"title":"1.2 预训练知识（Pretrained Knowledge）","description":"","frontmatter":{},"headers":[],"relativePath":"module_1/1.2预训练知识 [ Pretraind knowledge ].md","filePath":"module_1/1.2预训练知识 [ Pretraind knowledge ].md"}'),c={name:"module_1/1.2预训练知识 [ Pretraind knowledge ].md"};function u(g,t,m,A,I,b){return r(),e("div",null,[...t[0]||(t[0]=[l('<p><img src="'+i+'" alt="alt text"></p><h1 id="_1-2-预训练知识-pretrained-knowledge" tabindex="-1">1.2 预训练知识（Pretrained Knowledge） <a class="header-anchor" href="#_1-2-预训练知识-pretrained-knowledge" aria-label="Permalink to “1.2 预训练知识（Pretrained Knowledge）”">​</a></h1><p><img src="'+o+'" alt="alt text"></p><h2 id="什么是预训练知识" tabindex="-1">什么是预训练知识？ <a class="header-anchor" href="#什么是预训练知识" aria-label="Permalink to “什么是预训练知识？”">​</a></h2><p>你小时候是怎么学会写作的？大概是通过大量阅读。 <img src="'+d+'" alt="alt text"> AI 也是一样——AI 系统通过阅读来自互联网的海量文本，学习其中的语言模式。理解 AI 读过哪些内容，能帮助你更好地预测它的行为。</p><p>AI 模型可以回答各种各样的问题，例如：</p><ul><li>&quot;我把手机掉进汤里了，该怎么办？&quot;</li><li>&quot;为什么猫会盯着墙看，好像在看鬼一样？&quot;（原来猫能感知人类察觉不到的细微声音和动静）</li><li>&quot;发射到太空的那张黑胶唱片上录了什么？&quot;（NASA 的旅行者 1 号飞船，1970 年代发射，如今距地球约 250 亿英里，唱片上收录了 55 种语言的问候语）</li></ul><h2 id="alt-text" tabindex="-1"><img src="'+n+'" alt="alt text"> <a class="header-anchor" href="#alt-text" aria-label="Permalink to “”">​</a></h2><h2 id="ai-的知识来源" tabindex="-1">AI 的知识来源 <a class="header-anchor" href="#ai-的知识来源" aria-label="Permalink to “AI 的知识来源”">​</a></h2><p>AI 模型从多种多样的来源中学习，主要包括： <img src="'+s+'" alt="alt text"></p><table tabindex="0"><thead><tr><th>来源类型</th><th>示例</th></tr></thead><tbody><tr><td>社交媒体与论坛</td><td>Reddit、Quora 等</td></tr><tr><td>书籍</td><td>各类出版物</td></tr><tr><td>百科全书</td><td>Wikipedia 等</td></tr><tr><td>新闻网站</td><td>各大媒体</td></tr><tr><td>学术研究文章</td><td>论文、期刊</td></tr><tr><td>其他互联网内容</td><td>博客、网页等</td></tr></tbody></table><p>这些来源合计包含数万亿甚至数十万亿个词，共同构成了 AI 模型的&quot;大脑&quot;。</p><hr><h2 id="知识频率与可靠性" tabindex="-1">知识频率与可靠性 <a class="header-anchor" href="#知识频率与可靠性" aria-label="Permalink to “知识频率与可靠性”">​</a></h2><p>互联网上不同类型的内容出现频率不同，AI 的预训练知识也因此反映了这种分布规律。 <img src="'+p+'" alt="alt text"></p><p><strong>知识丰富的领域（互联网内容多）：</strong></p><ul><li>烹饪（普遍的人类经验，相关文章极多）</li><li>娱乐、电影、名人</li></ul><p><strong>知识相对有限的领域（互联网内容少）：</strong></p><ul><li>专业术语，如&quot;类星体&quot;（quasar）——由超大质量黑洞驱动的极亮天体，相关文章远少于烹饪类内容</li></ul><p><strong>语言分布：</strong></p><ul><li>互联网内容以英语为主</li><li>其他语言如粤语（全球超过 8000 万人使用）的内容占比不足 0.1%</li></ul><p><strong>AI 完全不了解的内容：</strong></p><ul><li>你公司的私有数据、内部文件等未公开在互联网上的信息</li></ul><blockquote><p><strong>实用规则：</strong> 某类信息在互联网上出现的频率越高，AI 对该话题的回答通常越可靠。</p></blockquote><hr><h2 id="ai-对拼写错误的容忍度" tabindex="-1">AI 对拼写错误的容忍度 <a class="header-anchor" href="#ai-对拼写错误的容忍度" aria-label="Permalink to “AI 对拼写错误的容忍度”">​</a></h2><p><img src="'+_+'" alt="alt text"> 由于 AI 从包含大量拼写错误的互联网内容中学习，它对错别字有很强的理解能力。例如：</p><ul><li><code>can you cook eggs in microwave</code>（有拼写错误）</li><li><code>can you cook eggs in the microwave</code>（标准写法）</li></ul><p>两者对 AI 来说几乎没有区别。因此，使用 AI 时不必花太多时间纠正每一个语法错误，快速输入即可。</p><hr><h2 id="预训练知识的局限性" tabindex="-1">预训练知识的局限性 <a class="header-anchor" href="#预训练知识的局限性" aria-label="Permalink to “预训练知识的局限性”">​</a></h2><p><img src="'+h+'" alt="alt text"> 预训练知识并非万能，主要存在以下局限：</p><ol><li><strong>包含误解和过时信息</strong>：互联网上本身存在大量错误内容，AI 也会从中学习</li><li><strong>缺乏实时信息</strong>：预训练知识有截止日期，无法获取最新动态</li></ol><p>掌握如何提示 AI 以减少误解、避免过时信息，是使用 AI 的重要技能之一。</p><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><ul><li>AI 的预训练知识来自互联网上的海量文本</li><li>知识的可靠性与该话题在互联网上的内容丰富程度正相关</li><li>AI 对拼写错误有较强容忍度，无需过度纠正</li><li>预训练知识不包含私有数据，也不具备实时信息能力</li><li>对于需要实时信息的场景，需要结合<strong>网络搜索</strong>功能使用</li></ul><p>下一节将介绍如何通过网络搜索弥补预训练知识的不足。</p><hr><p>预训练知识这个概念，让我想到一个很贴切的比喻：AI 就像一个博览群书、见多识广的人，但他在某个时间点之后就与世隔绝了，不再接触新信息。他能流利地谈论历史、科学、文化，但对昨天发生的事一无所知。</p><p>有几点值得特别关注：</p><p><strong>&quot;互联网偏见&quot;问题</strong>：AI 的知识分布并不均匀，它更擅长英语、更了解西方文化、更熟悉热门话题。这意味着当你用中文问一个小众的本地问题时，AI 的回答质量可能远不如用英文问一个全球性话题。这不是 AI 的&quot;错&quot;，而是训练数据本身的结构性偏差。</p><p><strong>拼写容忍度的背后逻辑</strong>：AI 之所以能理解错别字，是因为它见过无数人犯同样的错误——这其实是一种&quot;群体智慧&quot;的体现。但这也意味着，如果某个错误写法在互联网上极为普遍，AI 可能会把错的当成对的。</p><p><strong>私有数据的边界</strong>：公司内部文档、个人日记、未发布的代码——这些 AI 完全不知道。这既是隐私保护的优点，也是使用 AI 处理专业工作时需要额外补充上下文的原因。在实际工作中，我们往往需要把相关背景信息&quot;喂给&quot;AI，才能得到真正有用的答案。</p>',44)])])}const q=a(c,[["render",u]]);export{k as __pageData,q as default};
